window.__SEA_SPECIES_META__ = {"fish-clownfish": {"name": "Clownfish", "cat": "bony fish", "group": "damselfish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "It shelters unharmed among the stinging tentacles of sea anemones, protected by a layer of special mucus, in a famous mutualism."}, "fish-mandarinfish": {"name": "Mandarinfish", "cat": "bony fish", "group": "dragonet", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Its dazzling blue, orange and green pattern comes from true blue pigment cells, which are extremely rare in the animal kingdom."}, "fish-parrotfish": {"name": "Parrotfish", "cat": "bony fish", "group": "reef fish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "Its fused beak-like teeth scrape algae off coral, and it grinds up rock that it later excretes as fine white sand."}, "fish-wrasse": {"name": "Cleaner wrasse", "cat": "bony fish", "group": "wrasse", "hab": "coral reefs", "habKey": "reef", "diet": "parasites and dead skin", "art": "reef", "trait": "It runs a 'cleaning station,' picking parasites and dead skin from much larger fish that wait their turn to be groomed."}, "fish-angelfish": {"name": "Queen angelfish", "cat": "bony fish", "group": "angelfish", "hab": "coral reefs", "habKey": "reef", "diet": "sponges", "art": "reef", "trait": "Bright blue and yellow as an adult, it changes color dramatically as it grows from a striped juvenile."}, "fish-butterflyfish": {"name": "Butterflyfish", "cat": "bony fish", "group": "butterflyfish", "hab": "coral reefs", "habKey": "reef", "diet": "coral polyps", "art": "reef", "trait": "Many species mate for life and swim in pairs, and a dark eyespot near the tail can fool predators about which end is the head."}, "fish-surgeonfish": {"name": "Surgeonfish", "cat": "bony fish", "group": "surgeonfish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "It is named for a sharp, scalpel-like spine near its tail that it can flick out in self-defense."}, "fish-tang": {"name": "Blue tang", "cat": "bony fish", "group": "surgeonfish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "A vivid blue reef grazer with a yellow tail, it can play dead when threatened by lying motionless on its side."}, "fish-triggerfish": {"name": "Triggerfish", "cat": "bony fish", "group": "triggerfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "It can lock its first dorsal spine upright with a second 'trigger' spine, wedging itself into a crevice so predators cannot pull it out."}, "fish-pufferfish": {"name": "Pufferfish", "cat": "bony fish", "group": "pufferfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "When threatened it gulps water to swell into a spiny ball, and many species carry a potent toxin called tetrodotoxin."}, "fish-porcupinefish": {"name": "Porcupinefish", "cat": "bony fish", "group": "pufferfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Close relative of the puffer, it is covered in long spines that stand out stiffly when it inflates."}, "fish-boxfish": {"name": "Boxfish", "cat": "bony fish", "group": "boxfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Its body is encased in a rigid box of fused bony plates, so only its fins, eyes and mouth can move."}, "fish-lionfish": {"name": "Lionfish", "cat": "bony fish", "group": "scorpionfish", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "Its fan of venomous spines deters predators; native to the Indo-Pacific, it has become a damaging invader in the Atlantic."}, "fish-stonefish": {"name": "Stonefish", "cat": "bony fish", "group": "scorpionfish", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "Camouflaged as an algae-covered rock, it is considered the most venomous fish in the world."}, "fish-scorpionfish": {"name": "Scorpionfish", "cat": "bony fish", "group": "scorpionfish", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "A master of camouflage with venomous spines, it ambushes prey by sitting motionless and blending into the reef."}, "fish-frogfish": {"name": "Frogfish", "cat": "bony fish", "group": "anglerfish (shallow)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "It walks on leg-like fins and dangles a tiny built-in lure to draw prey within reach of its lightning-fast gulp."}, "fish-grouper": {"name": "Goliath grouper", "cat": "bony fish", "group": "grouper", "hab": "coral reefs", "habKey": "reef", "diet": "fish and squid", "art": "reef", "trait": "One of the largest reef fish, it can grow to hundreds of kilograms and makes a deep booming sound to warn off intruders."}, "fish-snapper": {"name": "Red snapper", "cat": "bony fish", "group": "snapper", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "A prized food fish, it gathers in large spawning groups and can live for over fifty years."}, "fish-grunt": {"name": "Grunt", "cat": "bony fish", "group": "grunt", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "It makes a grunting sound by grinding its throat teeth, amplified by its swim bladder."}, "fish-goatfish": {"name": "Goatfish", "cat": "bony fish", "group": "goatfish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "reef", "trait": "It uses a pair of whisker-like barbels under its chin to taste and probe the sand for buried prey."}, "fish-moorishidol": {"name": "Moorish idol", "cat": "bony fish", "group": "reef fish", "hab": "coral reefs", "habKey": "reef", "diet": "sponges", "art": "reef", "trait": "Famous for its bold black, white and yellow bands and a long trailing dorsal filament."}, "fish-damselfish": {"name": "Damselfish", "cat": "bony fish", "group": "damselfish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "Small but fearless, it farms and fiercely defends patches of algae, chasing away fish many times its size."}, "fish-anthias": {"name": "Anthias", "cat": "bony fish", "group": "reef fish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "These shimmering fish swarm above reefs by the thousands, and dominant females can change sex to become males."}, "fish-cardinalfish": {"name": "Cardinalfish", "cat": "bony fish", "group": "cardinalfish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "A mouthbrooder: the male carries the developing eggs in his mouth until they hatch."}, "fish-goby": {"name": "Goby", "cat": "bony fish", "group": "goby", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Among the smallest vertebrates, some gobies share a burrow with a shrimp, trading lookout duty for shelter."}, "fish-blenny": {"name": "Blenny", "cat": "bony fish", "group": "blenny", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "reef", "trait": "A small, big-eyed fish that perches in holes and crevices, darting out to feed and back to safety."}, "fish-hawkfish": {"name": "Hawkfish", "cat": "bony fish", "group": "hawkfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "It perches motionless on coral like a hawk on a branch, then pounces on passing prey."}, "fish-pipefish": {"name": "Pipefish", "cat": "bony fish", "group": "pipefish", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "plankton", "art": "reef", "trait": "A stretched-out relative of the seahorse; like seahorses, the male carries the eggs."}, "fish-seahorse": {"name": "Seahorse", "cat": "bony fish", "group": "seahorse", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "plankton", "art": "reef", "trait": "It is one of the few animals where the male becomes pregnant, brooding eggs in a belly pouch until they hatch."}, "fish-razorfish": {"name": "Razorfish (shrimpfish)", "cat": "crustacean", "group": "shrimpfish", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "plankton", "art": "tidepool", "trait": "It swims head-down in synchronized groups, hiding among sea urchin spines and seagrass."}, "fish-filefish": {"name": "Filefish", "cat": "bony fish", "group": "filefish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "Named for its rough, sandpapery skin, it can change color to blend with corals and weeds."}, "fish-rabbitfish": {"name": "Rabbitfish", "cat": "bony fish", "group": "rabbitfish", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "reef", "trait": "A reef grazer with venomous fin spines and a small, rabbit-like mouth for nibbling algae."}, "fish-sweetlips": {"name": "Sweetlips", "cat": "bony fish", "group": "grunt relative", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Juveniles wiggle dramatically to mimic toxic flatworms, gaining protection until they grow up."}, "fish-fusilier": {"name": "Fusilier", "cat": "bony fish", "group": "reef fish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "Streamlined and fast, it forms huge schools that sweep over reefs feeding on drifting plankton."}, "fish-soldierfish": {"name": "Soldierfish", "cat": "bony fish", "group": "squirrelfish relative", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "A red, big-eyed fish that hides in reef caves by day and emerges at night to feed."}, "fish-squirrelfish": {"name": "Squirrelfish", "cat": "bony fish", "group": "squirrelfish", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Its large eyes suit a nocturnal life, and it can make clicking sounds to communicate."}, "fish-bigeye": {"name": "Bigeye", "cat": "bony fish", "group": "bigeye", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "Enormous eyes gather faint light for hunting plankton at dusk and through the night."}, "fish-batfish": {"name": "Batfish", "cat": "bony fish", "group": "spadefish", "hab": "coral reefs", "habKey": "reef", "diet": "a wide range of foods", "art": "reef", "trait": "Tall and disc-shaped as an adult, its long-finned juveniles drift and sway to mimic dead leaves."}, "fish-jackfish": {"name": "Giant trevally", "cat": "bony fish", "group": "jack", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "reef", "trait": "A powerful, fast predator that hunts in packs and has even been filmed leaping to snatch seabirds."}, "fish-pompano": {"name": "Pompano", "cat": "bony fish", "group": "jack", "hab": "shallow coastal waters", "habKey": "coast", "diet": "small invertebrates", "art": "reef", "trait": "A swift, deep-bodied jack of sandy coasts, prized as a food fish."}, "fish-remora": {"name": "Remora", "cat": "bony fish", "group": "suckerfish", "hab": "the open ocean", "habKey": "open", "diet": "detritus and seabed matter", "art": "reef", "trait": "It hitchhikes on sharks, turtles and whales using a flat sucker on its head, eating scraps and parasites."}, "fish-cobia": {"name": "Cobia", "cat": "bony fish", "group": "cobia", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "reef", "trait": "Often mistaken for a shark, it shadows large animals and shipwrecks in search of crabs and fish."}, "fish-mullet": {"name": "Mullet", "cat": "bony fish", "group": "mullet", "hab": "shallow coastal waters", "habKey": "coast", "diet": "detritus and seabed matter", "art": "reef", "trait": "It feeds on algae and detritus in shallows and is famous for leaping clear of the water."}, "fish-mudskipper": {"name": "Mudskipper", "cat": "bony fish", "group": "goby (amphibious)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "small invertebrates", "art": "reef", "trait": "It can breathe air and 'walk' across mudflats on its fins, spending much of low tide out of the water."}, "fish-archerfish": {"name": "Archerfish", "cat": "bony fish", "group": "archerfish", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "small invertebrates", "art": "reef", "trait": "It shoots down insects above the water by spitting a precise jet of water from its mouth."}, "fish-flounder": {"name": "Flounder", "cat": "bony fish", "group": "flatfish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "fish", "art": "reef", "trait": "As it grows, one eye migrates to join the other so it can lie flat on the seabed, both eyes facing up."}, "fish-halibut": {"name": "Halibut", "cat": "bony fish", "group": "flatfish", "hab": "the continental shelf", "habKey": "shelf", "diet": "fish", "art": "reef", "trait": "A giant flatfish of cold seas, it can grow over two meters long and lies camouflaged on the bottom."}, "fish-sole": {"name": "Sole", "cat": "bony fish", "group": "flatfish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "worms and buried invertebrates", "art": "reef", "trait": "A small flatfish that buries in sand and feeds at night on worms and tiny invertebrates."}, "fish-stargazer": {"name": "Stargazer", "cat": "echinoderm", "group": "stargazer", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "fish", "art": "tidepool", "trait": "It buries in sand with only its upward-facing eyes and mouth showing, ambushing prey from below; some can even deliver an electric shock."}, "fish-toadfish": {"name": "Toadfish", "cat": "bony fish", "group": "toadfish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "reef", "trait": "The male hums loudly using its swim bladder to attract females, one of the loudest fish sounds."}, "fish-flyingfish": {"name": "Flying fish", "cat": "bony fish", "group": "flyingfish", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "reef", "trait": "It escapes predators by gliding above the surface on wing-like fins, sometimes for hundreds of meters."}, "fish-needlefish": {"name": "Needlefish", "cat": "bony fish", "group": "needlefish", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "reef", "trait": "A slender surface hunter with a long beak of sharp teeth that can skitter across the water at speed."}, "fish-halfbeak": {"name": "Halfbeak", "cat": "bony fish", "group": "halfbeak", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "reef", "trait": "Named for its single elongated lower jaw, it skims plankton just beneath the surface."}, "fish-tarpon": {"name": "Tarpon", "cat": "bony fish", "group": "tarpon", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "reef", "trait": "A large silver gamefish that can gulp air at the surface, letting it survive in low-oxygen water."}, "fish-snook": {"name": "Snook", "cat": "bony fish", "group": "snook", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "reef", "trait": "An ambush predator of mangroves and inlets, marked by a bold black line along its side."}, "fish-tuna-bluefin": {"name": "Bluefin tuna", "cat": "bony fish", "group": "tuna", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "reef", "trait": "One of the fastest, warmest-blooded fish, it keeps its muscles above water temperature to power long, high-speed migrations across oceans."}, "fish-tuna-yellowfin": {"name": "Yellowfin tuna", "cat": "bony fish", "group": "tuna", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "reef", "trait": "A sleek, powerful predator that often swims with dolphins and can sprint after fast prey."}, "fish-mackerel": {"name": "Atlantic mackerel", "cat": "bony fish", "group": "mackerel", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "reef", "trait": "It forms enormous fast-moving schools and is a key food fish for larger predators."}, "fish-wahoo": {"name": "Wahoo", "cat": "bony fish", "group": "mackerel relative", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "reef", "trait": "Among the fastest fish in the sea, it strikes prey in short, blistering bursts."}, "fish-kingmackerel": {"name": "King mackerel", "cat": "bony fish", "group": "mackerel", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "reef", "trait": "A swift coastal predator that migrates in schools and is a favorite of sport anglers."}, "fish-bonito": {"name": "Bonito", "cat": "bony fish", "group": "tuna relative", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "reef", "trait": "A small, striped tuna relative that hunts in fast schools near the surface."}, "fish-mahimahi": {"name": "Mahi-mahi", "cat": "marine mammal", "group": "dolphinfish", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "whale", "trait": "Brilliantly colored and fast-growing, it gathers under floating debris and fades to silver soon after being caught."}, "fish-marlin-blue": {"name": "Blue marlin", "cat": "bony fish", "group": "billfish", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "reef", "trait": "It uses its long spear-like bill to stun prey and is among the largest and fastest of all bony fish."}, "fish-sailfish": {"name": "Sailfish", "cat": "bony fish", "group": "billfish", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "reef", "trait": "Often called the fastest fish, it raises a huge sail-like fin to herd baitfish before striking."}, "fish-swordfish": {"name": "Swordfish", "cat": "bony fish", "group": "billfish", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "reef", "trait": "It has special tissue that warms its eyes and brain, sharpening its senses as it hunts in cold, deep water."}, "fish-bluefish": {"name": "Bluefish", "cat": "bony fish", "group": "bluefish", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "reef", "trait": "A ferocious schooling predator known for feeding frenzies that churn the water."}, "fish-jackmackerel": {"name": "Jack mackerel", "cat": "bony fish", "group": "jack", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "reef", "trait": "It forms vast offshore schools that support major fisheries and many predators."}, "fish-opah": {"name": "Opah (moonfish)", "cat": "bony fish", "group": "opah", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "reef", "trait": "A round, deep-living fish, it is one of the few known to be fully warm-blooded, heating its whole body."}, "fish-sunfish-mola": {"name": "Ocean sunfish (mola)", "cat": "bony fish", "group": "sunfish", "hab": "the open ocean", "habKey": "open", "diet": "jellyfish and soft-bodied animals", "art": "reef", "trait": "The heaviest bony fish in the world, this strange flattened giant basks at the surface and feeds largely on jellyfish."}, "fish-oarfish": {"name": "Oarfish", "cat": "bony fish", "group": "oarfish", "hab": "the deep sea", "habKey": "deep", "diet": "krill and small crustaceans", "art": "deepsea", "trait": "The longest bony fish, this ribbon-like deep-sea giant likely inspired old tales of sea serpents."}, "fish-herring": {"name": "Atlantic herring", "cat": "bony fish", "group": "herring", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "reef", "trait": "It schools in the millions and is a cornerstone food fish linking plankton to seabirds, whales and people."}, "fish-sardine": {"name": "Sardine", "cat": "bony fish", "group": "herring relative", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "reef", "trait": "Its huge migrating schools, like South Africa's sardine run, draw predators from sharks to dolphins to gannets."}, "fish-anchovy": {"name": "Anchovy", "cat": "bony fish", "group": "anchovy", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "reef", "trait": "Tiny but vital, dense anchovy schools fuel some of the world's largest fisheries and feed countless predators."}, "fish-menhaden": {"name": "Menhaden", "cat": "bony fish", "group": "herring relative", "hab": "shallow coastal waters", "habKey": "coast", "diet": "tiny filtered plankton", "art": "reef", "trait": "A filter feeder that strains plankton, it is so important as food and fertilizer it has been called 'the most important fish in the sea.'"}, "fish-capelin": {"name": "Capelin", "cat": "bony fish", "group": "smelt", "hab": "cold polar seas", "habKey": "polar", "diet": "plankton", "art": "reef", "trait": "A small cold-water fish whose mass spawning feeds whales, seabirds and cod in the far north."}, "fish-barracuda": {"name": "Great barracuda", "cat": "bony fish", "group": "barracuda", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "A fast, fang-toothed ambush predator that relies on bursts of speed and is drawn to shiny objects."}, "fish-anglerfish-deep": {"name": "Deep-sea anglerfish", "cat": "bony fish", "group": "anglerfish", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "It dangles a glowing, bacteria-lit lure to draw prey out of the darkness; in some species the tiny male fuses permanently to the female."}, "fish-viperfish": {"name": "Viperfish", "cat": "bony fish", "group": "dragonfish relative", "hab": "the deep sea", "habKey": "deep", "diet": "fish and squid", "art": "deepsea", "trait": "Its fangs are so long they do not fit inside its mouth, and a glowing lure helps tempt prey close."}, "fish-dragonfish": {"name": "Black dragonfish", "cat": "bony fish", "group": "dragonfish", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "It produces and even sees red light, an invisible 'searchlight' that most deep-sea animals cannot detect."}, "fish-gulper": {"name": "Gulper eel (pelican eel)", "cat": "bony fish", "group": "eel", "hab": "the deep sea", "habKey": "deep", "diet": "fish and squid", "art": "deepsea", "trait": "Its enormous, balloon-like mouth can engulf prey larger than itself in the food-poor deep."}, "fish-hatchetfish": {"name": "Hatchetfish", "cat": "bony fish", "group": "hatchetfish", "hab": "the ocean twilight zone", "habKey": "twilight", "diet": "plankton", "art": "deepsea", "trait": "Light organs on its belly match the dim glow from above, erasing its silhouette from predators below."}, "fish-lanternfish": {"name": "Lanternfish", "cat": "seabird", "group": "lanternfish", "hab": "the ocean twilight zone", "habKey": "twilight", "diet": "zooplankton", "art": "deepsea", "trait": "Rows of light organs and nightly migrations to the surface make these among the most abundant fish on Earth."}, "fish-bristlemouth": {"name": "Bristlemouth", "cat": "bony fish", "group": "bristlemouth", "hab": "the ocean twilight zone", "habKey": "twilight", "diet": "plankton", "art": "deepsea", "trait": "Tiny and glowing, bristlemouths may be the most numerous vertebrates on the planet."}, "fish-fangtooth": {"name": "Fangtooth", "cat": "bony fish", "group": "fangtooth", "hab": "the deep sea", "habKey": "deep", "diet": "fish and squid", "art": "deepsea", "trait": "Despite a fearsome look and the largest teeth for its size of any fish, it is only the size of a fist."}, "fish-tripod": {"name": "Tripodfish", "cat": "bony fish", "group": "deep-sea fish", "hab": "the deep sea", "habKey": "deep", "diet": "plankton", "art": "deepsea", "trait": "It stands on three long, stiff fin rays like a tripod, facing the current to catch drifting food."}, "fish-grenadier": {"name": "Grenadier (rattail)", "cat": "bony fish", "group": "grenadier", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "A long-tailed, big-headed scavenger that is among the most common fish on the deep seafloor."}, "fish-blobfish": {"name": "Blobfish", "cat": "bony fish", "group": "fathead sculpin", "hab": "the deep sea", "habKey": "deep", "diet": "small invertebrates", "art": "deepsea", "trait": "Gelatinous and nearly weightless, it drifts just above the seabed; its famous 'blobby' look only appears once it is hauled to the surface."}, "fish-coffinfish": {"name": "Coffinfish", "cat": "bony fish", "group": "deep-sea anglerfish", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "A small deep-sea angler that can gulp and hold water, puffing up and slowing its breathing to save energy."}, "fish-lizardfish": {"name": "Deep-sea lizardfish", "cat": "bony fish", "group": "lizardfish", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "A patient bottom ambusher with a toothy grin that waits motionless for prey to pass."}, "fish-snailfish-deep": {"name": "Hadal snailfish", "cat": "mollusc", "group": "snailfish", "hab": "the deep sea", "habKey": "deep", "diet": "crabs and shellfish", "art": "deepsea", "trait": "Soft and gelatinous, it lives deeper than 8,000 m, the deepest fish ever recorded."}, "fish-cusk-eel": {"name": "Cusk-eel", "cat": "bony fish", "group": "cusk-eel", "hab": "the deep sea", "habKey": "deep", "diet": "small invertebrates", "art": "deepsea", "trait": "Some cusk-eels hold the record for the deepest-living fish caught from the very bottom of ocean trenches."}, "fish-coelacanth": {"name": "Coelacanth", "cat": "bony fish", "group": "lobe-finned fish", "hab": "the deep sea", "habKey": "deep", "diet": "fish and squid", "art": "deepsea", "trait": "A 'living fossil' once thought extinct for millions of years, it has fleshy, limb-like fins and was rediscovered alive in 1938."}, "fish-chimaera": {"name": "Chimaera (ratfish)", "cat": "bony fish", "group": "cartilaginous fish", "hab": "the deep sea", "habKey": "deep", "diet": "crabs and shellfish", "art": "deepsea", "trait": "A deep-dwelling relative of sharks with a venomous spine and a soft, tapering body."}, "fish-moray": {"name": "Moray eel", "cat": "bony fish", "group": "eel", "hab": "coral reefs", "habKey": "reef", "diet": "fish and squid", "art": "reef", "trait": "It has a second set of jaws in its throat that shoot forward to grab and pull prey down, and it gapes to breathe, not to threaten."}, "fish-gardeneel": {"name": "Garden eel", "cat": "bony fish", "group": "eel", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "plankton", "art": "reef", "trait": "Colonies poke from the sand swaying in the current to grab plankton, retreating into their burrows when threatened."}, "fish-conger": {"name": "Conger eel", "cat": "bony fish", "group": "eel", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "fish and squid", "art": "reef", "trait": "A large nocturnal eel that shelters in rocky holds and wrecks, emerging at night to hunt."}, "fish-electriceel": {"name": "Electric eel", "cat": "bony fish", "group": "knifefish (not a true eel)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "reef", "trait": "Despite the name it is not a true eel; it can deliver a powerful electric shock to stun prey and defend itself."}, "fish-freshwater-eel": {"name": "American eel", "cat": "bony fish", "group": "eel", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "small invertebrates", "art": "reef", "trait": "It hatches far out in the Sargasso Sea, migrates into rivers to grow, then returns to the open ocean to spawn."}, "fish-lamprey": {"name": "Sea lamprey", "cat": "bony fish", "group": "jawless fish", "hab": "shallow coastal waters", "habKey": "coast", "diet": "blood and tissue as a parasite", "art": "reef", "trait": "One of the oldest fish lineages, it has no jaws; instead a round, toothed sucker latches onto other fish."}, "fish-hagfish": {"name": "Hagfish", "cat": "bony fish", "group": "jawless fish", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "When attacked it instantly unleashes clouds of slime that clog a predator's gills, and it can tie itself in a knot to escape."}, "fish-sturgeon": {"name": "Sturgeon", "cat": "bony fish", "group": "sturgeon", "hab": "shallow coastal waters", "habKey": "coast", "diet": "worms and buried invertebrates", "art": "reef", "trait": "An ancient armored fish that can live over a century and is prized (and threatened) for its eggs, sold as caviar."}, "fish-seadragon": {"name": "Leafy seadragon", "cat": "bony fish", "group": "seahorse relative", "hab": "kelp forests", "habKey": "kelp", "diet": "plankton", "art": "reef", "trait": "Adorned with leaf-shaped flaps, it drifts through seaweed in near-perfect camouflage; like seahorses, the male carries the eggs."}, "shark-greatwhite": {"name": "Great white shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "seals, fish and squid", "art": "shark", "trait": "A warm-bodied apex predator, it can launch fully out of the water to ambush seals from below."}, "shark-tiger": {"name": "Tiger shark", "cat": "shark", "group": "shark", "hab": "warm tropical seas", "habKey": "tropic", "diet": "a wide range of foods", "art": "shark", "trait": "Nicknamed the ocean's garbage can, it eats almost anything and bears dark stripes that fade with age."}, "shark-bull": {"name": "Bull shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "shark", "trait": "Uniquely tolerant of fresh water, it swims far up rivers and into lakes well away from the sea."}, "shark-hammerhead": {"name": "Great hammerhead", "cat": "shark", "group": "shark", "hab": "warm tropical seas", "habKey": "tropic", "diet": "ray", "art": "shark", "trait": "Its wide, flat head spreads its sensory organs for a better sweep, and it uses the 'hammer' to pin stingrays."}, "shark-mako": {"name": "Shortfin mako", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "shark", "trait": "The fastest shark, it is warm-bodied and can leap high out of the water chasing fast prey."}, "shark-blue": {"name": "Blue shark", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "shark", "trait": "Slender and far-roaming, it makes some of the longest migrations of any shark across entire oceans."}, "shark-whaleshark": {"name": "Whale shark", "cat": "shark", "group": "shark", "hab": "warm tropical seas", "habKey": "tropic", "diet": "plankton", "art": "shark", "trait": "The largest fish in the world, this gentle giant cruises slowly, filtering plankton from huge mouthfuls of water."}, "shark-basking": {"name": "Basking shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "shark", "trait": "The second-largest fish, it filters plankton with its cavernous mouth while swimming near the surface."}, "shark-megamouth": {"name": "Megamouth shark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "plankton", "art": "deepsea", "trait": "A rare deep-water filter feeder, it was unknown to science until 1976."}, "shark-thresher": {"name": "Thresher shark", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "shark", "trait": "It stuns schooling fish by whipping its enormously long tail like a weapon."}, "shark-nurse": {"name": "Nurse shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "shark", "trait": "A slow, docile bottom-dweller, it rests by day and uses suction to slurp prey from crevices at night."}, "shark-lemon": {"name": "Lemon shark", "cat": "shark", "group": "shark", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "shark", "trait": "Yellow-tinged for camouflage over sand, its pups grow up in the shelter of mangrove nurseries."}, "shark-reef-blacktip": {"name": "Blacktip reef shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "shark", "trait": "A common, shy reef shark recognized by the black tips on its fins, often seen in shallow lagoons."}, "shark-reef-whitetip": {"name": "Whitetip reef shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "shark", "trait": "It rests in caves by day, then hunts cooperatively at night, wriggling into crevices after prey."}, "shark-sandtiger": {"name": "Sand tiger shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "shark", "trait": "Fierce-looking but fairly placid, it gulps air at the surface to hover motionless in the water."}, "shark-goblin": {"name": "Goblin shark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "A rare deep-sea 'living fossil' whose jaws shoot far forward to snatch prey, then snap back."}, "shark-frilled": {"name": "Frilled shark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "squid", "art": "deepsea", "trait": "An eel-like deep-water shark with frilly gills and rows of needle teeth, little changed for millions of years."}, "shark-cookiecutter": {"name": "Cookiecutter shark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "Small but bold, it gouges round plugs of flesh from animals far larger than itself, including whales."}, "shark-greenland": {"name": "Greenland shark", "cat": "shark", "group": "shark", "hab": "cold polar seas", "habKey": "polar", "diet": "seals, fish and squid", "art": "shark", "trait": "A slow Arctic giant, it is the longest-lived vertebrate known, with individuals estimated to be centuries old."}, "shark-wobbegong": {"name": "Wobbegong", "cat": "shark", "group": "carpet shark", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "shark", "trait": "A flattened, frilled bottom shark whose camouflage makes it nearly invisible as it ambushes prey."}, "shark-angel": {"name": "Angelshark", "cat": "shark", "group": "shark", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "fish", "art": "shark", "trait": "Flat and ray-like, it buries in sand and bursts upward to seize fish swimming overhead."}, "shark-saw": {"name": "Sawshark", "cat": "shark", "group": "shark", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "shark", "trait": "It uses its long, tooth-edged snout to slash through schools of fish and probe the seabed."}, "shark-dogfish": {"name": "Spiny dogfish", "cat": "shark", "group": "shark", "hab": "the continental shelf", "habKey": "shelf", "diet": "fish", "art": "shark", "trait": "A small, abundant schooling shark with mildly venomous spines, often studied in classrooms."}, "shark-catshark": {"name": "Catshark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "small invertebrates", "art": "deepsea", "trait": "A small bottom shark that lays tough egg cases known as 'mermaid's purses.'"}, "shark-port-jackson": {"name": "Port Jackson shark", "cat": "shark", "group": "shark", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "crabs and shellfish", "art": "shark", "trait": "It crushes shellfish with flat back teeth and lays distinctive spiral-shaped egg cases."}, "shark-zebra": {"name": "Zebra (leopard) shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "shark", "trait": "Born with stripes that break into spots as it grows, it threads its slender body through reef crevices."}, "shark-epaulette": {"name": "Epaulette shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "shark", "trait": "It 'walks' across exposed reef flats on its fins and can survive very low oxygen at low tide."}, "shark-silky": {"name": "Silky shark", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "shark", "trait": "Smooth-skinned and curious, it is one of the most common open-ocean sharks."}, "shark-oceanic-whitetip": {"name": "Oceanic whitetip shark", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "shark", "trait": "A bold open-ocean wanderer with rounded, white-tipped fins, once among the most abundant large animals at sea."}, "ray-manta": {"name": "Giant manta ray", "cat": "ray", "group": "ray", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "ray", "trait": "The largest ray, with a wingspan over seven meters, it filters plankton and has the largest brain of any fish."}, "ray-devil": {"name": "Devil ray (mobula)", "cat": "ray", "group": "ray", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "ray", "trait": "Smaller cousins of mantas, they sometimes leap and somersault high out of the water in groups."}, "ray-eagle": {"name": "Spotted eagle ray", "cat": "ray", "group": "ray", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "ray", "trait": "Graceful and spotted, it flaps like a bird and uses a duck-like snout to dig clams from the sand."}, "ray-stingray-southern": {"name": "Southern stingray", "cat": "ray", "group": "ray", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "ray", "trait": "It glides over sand and rests buried with only its eyes showing, armed with a venomous tail barb for defense."}, "ray-bluespotted": {"name": "Blue-spotted ribbontail ray", "cat": "ray", "group": "ray", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "ray", "trait": "Vivid blue spots warn of its venomous spines as it forages over coral sand."}, "ray-electric": {"name": "Electric ray (torpedo)", "cat": "ray", "group": "ray", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "fish", "art": "ray", "trait": "It can deliver a strong electric shock from special organs to stun prey and ward off attackers."}, "ray-cownose": {"name": "Cownose ray", "cat": "ray", "group": "ray", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "ray", "trait": "It travels in large migrating schools and uses its snout to uncover buried shellfish."}, "ray-sawfish": {"name": "Sawfish", "cat": "ray", "group": "ray", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "ray", "trait": "Though shaped like a shark, it is a ray; its toothed saw senses and slashes prey, and most species are critically endangered."}, "ray-guitarfish": {"name": "Guitarfish", "cat": "ray", "group": "ray", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "ray", "trait": "A shark-shaped ray that bridges the two groups, cruising sandy shallows for shellfish."}, "ray-skate": {"name": "Skate", "cat": "ray", "group": "ray", "hab": "the continental shelf", "habKey": "shelf", "diet": "crabs and shellfish", "art": "ray", "trait": "Unlike most stingrays it has no venomous barb, and it lays eggs in tough cases on the seabed."}, "ray-manta-reef": {"name": "Reef manta ray", "cat": "ray", "group": "ray", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "ray", "trait": "It visits reef 'cleaning stations' where small fish remove parasites, and feeds by funneling plankton with its head fins."}, "ray-torpedo-marbled": {"name": "Marbled electric ray", "cat": "ray", "group": "ray", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "fish", "art": "ray", "trait": "Camouflaged on the seabed, it ambushes fish and stuns them with an electric jolt."}, "mammal-bluewhale": {"name": "Blue whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "krill and small crustaceans", "art": "whale", "trait": "The largest animal ever to live, it feeds on tiny krill and its low calls are among the loudest made by any animal."}, "mammal-finwhale": {"name": "Fin whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "krill and small crustaceans", "art": "whale", "trait": "The second-largest animal, nicknamed the 'greyhound of the sea' for its speed, with oddly asymmetrical jaw coloring."}, "mammal-humpback": {"name": "Humpback whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "krill and small crustaceans", "art": "whale", "trait": "Famous for long, complex songs and for blowing nets of bubbles to corral fish before lunging through them."}, "mammal-graywhale": {"name": "Gray whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "worms and buried invertebrates", "art": "whale", "trait": "It makes one of the longest mammal migrations and feeds by rolling on its side to suck prey from seafloor mud."}, "mammal-rightwhale": {"name": "North Atlantic right whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "zooplankton", "art": "whale", "trait": "Slow and rich in blubber, it skims clouds of tiny plankton; only a few hundred survive, making it critically endangered."}, "mammal-bowhead": {"name": "Bowhead whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "cold polar seas", "habKey": "polar", "diet": "zooplankton", "art": "whale", "trait": "An Arctic specialist that can break through sea ice and may live over two hundred years."}, "mammal-minke": {"name": "Minke whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "krill and small crustaceans", "art": "whale", "trait": "One of the smallest and most common baleen whales, fast and often seen alone."}, "mammal-seiwhale": {"name": "Sei whale", "cat": "marine mammal", "group": "baleen whale (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "zooplankton", "art": "whale", "trait": "One of the fastest whales, it skims through swarms of copepods near the surface."}, "mammal-spermwhale": {"name": "Sperm whale", "cat": "marine mammal", "group": "toothed whale (marine mammal)", "hab": "the deep sea", "habKey": "deep", "diet": "squid", "art": "deepsea", "trait": "It has the largest brain of any animal and dives over a kilometer down to hunt giant squid in the dark."}, "mammal-pygmysperm": {"name": "Pygmy sperm whale", "cat": "marine mammal", "group": "toothed whale (marine mammal)", "hab": "the deep sea", "habKey": "deep", "diet": "squid", "art": "deepsea", "trait": "When startled it releases a cloud of reddish 'ink' to confuse predators as it escapes."}, "mammal-beaked": {"name": "Cuvier's beaked whale", "cat": "marine mammal", "group": "toothed whale (marine mammal)", "hab": "the deep sea", "habKey": "deep", "diet": "squid", "art": "deepsea", "trait": "It holds the record for the deepest and longest dives of any mammal, reaching near three kilometers down."}, "mammal-narwhal": {"name": "Narwhal", "cat": "marine mammal", "group": "toothed whale (marine mammal)", "hab": "cold polar seas", "habKey": "polar", "diet": "fish and squid", "art": "whale", "trait": "The male's spiraled tusk is actually a giant tooth packed with nerves, earning it the title 'unicorn of the sea.'"}, "mammal-beluga": {"name": "Beluga whale", "cat": "marine mammal", "group": "toothed whale (marine mammal)", "hab": "cold polar seas", "habKey": "polar", "diet": "fish", "art": "whale", "trait": "White and very vocal, it has a flexible neck and a bulging forehead 'melon' it uses to focus sound."}, "mammal-orca": {"name": "Orca (killer whale)", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "many oceans worldwide", "habKey": "global", "diet": "seals, fish and squid", "art": "whale", "trait": "The largest dolphin and a top ocean predator, it hunts in family pods with distinct cultures and hunting traditions."}, "mammal-bottlenose": {"name": "Bottlenose dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Highly intelligent and social, some use sponges as tools to protect their snouts while foraging."}, "mammal-common-dolphin": {"name": "Common dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "whale", "trait": "It travels in fast, leaping 'superpods' that can number in the thousands."}, "mammal-spinner": {"name": "Spinner dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "whale", "trait": "Named for leaping and spinning in the air, it rests by day and hunts the twilight zone by night."}, "mammal-spotted-dolphin": {"name": "Atlantic spotted dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Born unspotted, it gains more spots with age until it is heavily speckled."}, "mammal-risso": {"name": "Risso's dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "whale", "trait": "Older individuals are crisscrossed with white scars from squid and from social play."}, "mammal-pilot": {"name": "Pilot whale", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "whale", "trait": "Despite the name it is a large dolphin, living in tight-knit pods that follow elder leaders."}, "mammal-falsekiller": {"name": "False killer whale", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "whale", "trait": "A large social dolphin known to share food and to interact playfully with other dolphin species."}, "mammal-harborporpoise": {"name": "Harbor porpoise", "cat": "marine mammal", "group": "porpoise (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Small and shy, it must eat almost constantly to fuel its fast metabolism in cool coastal waters."}, "mammal-dalls": {"name": "Dall's porpoise", "cat": "marine mammal", "group": "porpoise (marine mammal)", "hab": "cold polar seas", "habKey": "polar", "diet": "fish", "art": "whale", "trait": "One of the fastest small cetaceans, it throws up a distinctive 'rooster tail' of spray as it speeds along."}, "mammal-vaquita": {"name": "Vaquita", "cat": "marine mammal", "group": "porpoise (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "The world's smallest and most endangered marine mammal, with only a handful left in Mexico's Gulf of California."}, "mammal-amazon-river": {"name": "River dolphin", "cat": "marine mammal", "group": "dolphin (marine mammal)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "whale", "trait": "River dolphins navigate murky water largely by echolocation, and some are tinted pink."}, "mammal-harborseal": {"name": "Harbor seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Its sensitive whiskers can track the invisible wake a fish leaves in the water, even in the dark."}, "mammal-graysealatl": {"name": "Gray seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Recognized by its long, horse-like snout, it hauls out on rocky shores in large breeding colonies."}, "mammal-elephantseal": {"name": "Elephant seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "whale", "trait": "The largest seal, the male sports a huge inflatable nose, and it dives deeper and longer than almost any other seal."}, "mammal-leopardseal": {"name": "Leopard seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "seals, fish and squid", "art": "whale", "trait": "A powerful Antarctic predator of penguins and other seals, it also filters tiny krill with specialized teeth."}, "mammal-weddell": {"name": "Weddell seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "fish", "art": "whale", "trait": "It lives farther south than almost any mammal, gnawing breathing holes in the Antarctic ice."}, "mammal-crabeater": {"name": "Crabeater seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "krill and small crustaceans", "art": "whale", "trait": "Despite its name it eats krill, sieving them through finely cusped teeth; it may be the most numerous large wild mammal on Earth."}, "mammal-ross": {"name": "Ross seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "squid", "art": "whale", "trait": "The smallest and least-seen Antarctic seal, with large eyes and an unusual chirping, siren-like call."}, "mammal-harp": {"name": "Harp seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "fish", "art": "whale", "trait": "Its fluffy white pups are born on the sea ice and molt to the harp-marked coat of adults."}, "mammal-ringed": {"name": "Ringed seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "fish", "art": "whale", "trait": "The main prey of polar bears, it keeps Arctic breathing holes open all winter using strong claws."}, "mammal-monkseal": {"name": "Hawaiian monk seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "warm tropical seas", "habKey": "tropic", "diet": "fish", "art": "whale", "trait": "One of the rarest seals, it is a warm-water species found mainly around the Hawaiian Islands."}, "mammal-bearded": {"name": "Bearded seal", "cat": "marine mammal", "group": "true seal (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "crabs and shellfish", "art": "whale", "trait": "Its thick whiskers help it find clams and crabs on the Arctic seabed."}, "mammal-californiasealion": {"name": "California sea lion", "cat": "marine mammal", "group": "sea lion (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "Loud and acrobatic, it can rotate its hind flippers to walk on land and is a favorite at marine shows."}, "mammal-stellersealion": {"name": "Steller sea lion", "cat": "marine mammal", "group": "sea lion (marine mammal)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "whale", "trait": "The largest sea lion, the bulls grow huge and defend crowded breeding rookeries."}, "mammal-fursealnorth": {"name": "Northern fur seal", "cat": "marine mammal", "group": "fur seal (marine mammal)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "whale", "trait": "Dense fur, not blubber, keeps it warm, and it spends months at sea between breeding seasons."}, "mammal-walrus": {"name": "Walrus", "cat": "marine mammal", "group": "walrus (marine mammal)", "hab": "polar ice edges", "habKey": "ice", "diet": "crabs and shellfish", "art": "whale", "trait": "Both sexes bear long tusks used to haul out onto ice and to spar, and it vacuums clams from the seabed with its mouth."}, "mammal-seaotter": {"name": "Sea otter", "cat": "marine mammal", "group": "sea otter (marine mammal)", "hab": "kelp forests", "habKey": "kelp", "diet": "sea urchins and shellfish", "art": "whale", "trait": "Lacking blubber, it relies on the densest fur of any animal and uses rocks as tools to crack open shellfish."}, "mammal-manatee": {"name": "Manatee", "cat": "marine mammal", "group": "sirenian (marine mammal)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "seagrass and water plants", "art": "whale", "trait": "A gentle, slow-moving plant-eater of warm shallows, it grazes on seagrass and is sometimes called a 'sea cow.'"}, "mammal-dugong": {"name": "Dugong", "cat": "marine mammal", "group": "sirenian (marine mammal)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "seagrass and water plants", "art": "whale", "trait": "A relative of the manatee with a dolphin-like fluked tail, it grazes seagrass meadows of the Indo-Pacific."}, "mammal-polarbear": {"name": "Polar bear", "cat": "marine mammal", "group": "marine mammal (bear)", "hab": "polar ice edges", "habKey": "ice", "diet": "seals, fish and squid", "art": "whale", "trait": "Classed as a marine mammal, it hunts seals from the sea ice and can swim for days between ice floes."}, "reptile-greenturtle": {"name": "Green sea turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "seagrass and water plants", "art": "turtle", "trait": "Unusual among sea turtles, the adult is mostly vegetarian, grazing seagrass and algae; its fat is what gives it a greenish tint."}, "reptile-loggerhead": {"name": "Loggerhead turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "turtle", "trait": "Its powerful jaws crush hard-shelled prey like crabs and conchs, and it navigates oceans using Earth's magnetic field."}, "reptile-leatherback": {"name": "Leatherback turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "the open ocean", "habKey": "open", "diet": "jellyfish and soft-bodied animals", "art": "turtle", "trait": "The largest turtle, it has a leathery shell instead of a hard one and feeds almost entirely on jellyfish."}, "reptile-hawksbill": {"name": "Hawksbill turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "coral reefs", "habKey": "reef", "diet": "sponges", "art": "turtle", "trait": "Its narrow beak reaches into reef crevices for sponges, and its beautiful shell has long made it a target of trade."}, "reptile-oliveridley": {"name": "Olive ridley turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "turtle", "trait": "It is famous for the 'arribada,' when thousands of females come ashore to nest on the same beach at once."}, "reptile-kempsridley": {"name": "Kemp's ridley turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "turtle", "trait": "The smallest and most endangered sea turtle, it nests mainly on a few beaches in the Gulf of Mexico."}, "reptile-flatback": {"name": "Flatback turtle", "cat": "sea turtle", "group": "sea turtle (reptile)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "jellyfish and soft-bodied animals", "art": "turtle", "trait": "Found only around Australia, it has a low, flattened shell and stays close to its home shores."}, "reptile-seasnake": {"name": "Sea snake", "cat": "marine reptile", "group": "marine reptile (snake)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "turtle", "trait": "Fully aquatic and highly venomous, it can absorb some oxygen through its skin during long dives."}, "reptile-seakrait": {"name": "Sea krait", "cat": "marine reptile", "group": "marine reptile (snake)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "turtle", "trait": "Unlike true sea snakes it returns to land to rest, drink fresh water and lay eggs."}, "reptile-marineiguana": {"name": "Marine iguana", "cat": "marine reptile", "group": "marine reptile (lizard)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "turtle", "trait": "Found only on the Galápagos, it dives to graze underwater algae and sneezes out excess salt."}, "reptile-saltwatercroc": {"name": "Saltwater crocodile", "cat": "marine reptile", "group": "marine reptile (crocodile)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "fish", "art": "turtle", "trait": "The largest living reptile, it tolerates the sea and can travel long distances between coasts on ocean currents."}, "bird-wanderingalbatross": {"name": "Wandering albatross", "cat": "seabird", "group": "seabird", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "ocean", "trait": "It has the longest wingspan of any bird and can glide thousands of kilometers across the Southern Ocean with barely a wingbeat."}, "bird-laysanalbatross": {"name": "Laysan albatross", "cat": "seabird", "group": "seabird", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "ocean", "trait": "It often mates for life and returns to the same nesting island year after year, sometimes for decades."}, "bird-emperorpenguin": {"name": "Emperor penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "polar ice edges", "habKey": "ice", "diet": "fish", "art": "ocean", "trait": "The largest penguin, the male incubates a single egg on his feet through the brutal Antarctic winter."}, "bird-kingpenguin": {"name": "King penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "cold polar seas", "habKey": "polar", "diet": "fish", "art": "ocean", "trait": "It raises its chick over more than a year, and the fluffy brown chicks were once mistaken for a different species."}, "bird-adeliepenguin": {"name": "Adélie penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "polar ice edges", "habKey": "ice", "diet": "krill and small crustaceans", "art": "ocean", "trait": "It builds nests of pebbles on the Antarctic coast and porpoises through the water to escape leopard seals."}, "bird-gentoo": {"name": "Gentoo penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "polar ice edges", "habKey": "ice", "diet": "krill and small crustaceans", "art": "ocean", "trait": "Recognized by a white head patch, it is the fastest swimming bird, reaching high speeds underwater."}, "bird-galapagospenguin": {"name": "Galápagos penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "warm tropical seas", "habKey": "tropic", "diet": "fish", "art": "ocean", "trait": "The only penguin found north of the equator, it relies on cool currents to survive the tropics."}, "bird-littleblue": {"name": "Little blue penguin", "cat": "seabird", "group": "seabird (penguin)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "The smallest penguin, it comes ashore after dark and nests in burrows along southern coasts."}, "bird-atlanticpuffin": {"name": "Atlantic puffin", "cat": "seabird", "group": "seabird (auk)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "Its colorful bill can hold many small fish at once, lined up crosswise, as it ferries food to its chick."}, "bird-commonmurre": {"name": "Common murre", "cat": "seabird", "group": "seabird (auk)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "It nests shoulder to shoulder on bare cliff ledges and 'flies' underwater using its wings to chase fish."}, "bird-razorbill": {"name": "Razorbill", "cat": "seabird", "group": "seabird (auk)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "A close relative of the extinct great auk, it dives deep on rapid wingbeats to catch fish."}, "bird-northerngannet": {"name": "Northern gannet", "cat": "seabird", "group": "seabird", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "It plunge-dives from high up, hitting the water like an arrow with air sacs cushioning the impact."}, "bird-bluefoocedbooby": {"name": "Blue-footed booby", "cat": "seabird", "group": "seabird", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "The male shows off his bright blue feet in a high-stepping courtship dance; bluer feet signal a healthier bird."}, "bird-brownpelican": {"name": "Brown pelican", "cat": "seabird", "group": "seabird", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "It dives headfirst and scoops fish into the large stretchy pouch under its bill."}, "bird-frigatebird": {"name": "Magnificent frigatebird", "cat": "seabird", "group": "seabird", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "The male inflates a huge red throat pouch to attract mates, and it often steals food from other seabirds in midair."}, "bird-tropicbird": {"name": "Red-tailed tropicbird", "cat": "seabird", "group": "seabird", "hab": "the open ocean", "habKey": "open", "diet": "fish and squid", "art": "ocean", "trait": "It ranges far over tropical seas, trailing long tail streamers and plunge-diving for fish and squid."}, "bird-arctictern": {"name": "Arctic tern", "cat": "seabird", "group": "seabird (tern)", "hab": "many oceans worldwide", "habKey": "global", "diet": "fish", "art": "ocean", "trait": "It migrates from the Arctic to the Antarctic and back each year, the longest migration of any animal."}, "bird-sootytern": {"name": "Sooty tern", "cat": "seabird", "group": "seabird (tern)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "It can stay aloft over the ocean for years at a time, snatching prey from the surface without landing."}, "bird-commontern": {"name": "Common tern", "cat": "seabird", "group": "seabird (tern)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "A graceful diver that hovers then plunges for small fish, nesting in noisy coastal colonies."}, "bird-herringgull": {"name": "Herring gull", "cat": "seabird", "group": "seabird (gull)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "a wide range of foods", "art": "ocean", "trait": "A clever, adaptable scavenger; chicks peck a red spot on the parent's bill to beg for food."}, "bird-kittiwake": {"name": "Black-legged kittiwake", "cat": "seabird", "group": "seabird (gull)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "Unlike most gulls it spends winters far out at sea and nests on tiny cliff ledges."}, "bird-cormorant": {"name": "Cormorant", "cat": "seabird", "group": "seabird", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "ocean", "trait": "It pursues fish underwater, then must spread its wings to dry because its feathers are not fully waterproof."}, "bird-shag": {"name": "European shag", "cat": "seabird", "group": "seabird (cormorant)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "fish", "art": "ocean", "trait": "A slender cormorant of rocky coasts, it dives from the surface to chase fish near the seabed."}, "bird-skua": {"name": "Great skua", "cat": "seabird", "group": "seabird", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "A piratical seabird that chases others to make them drop their catch, and will defend its nest fiercely."}, "bird-petrel-storm": {"name": "Storm petrel", "cat": "seabird", "group": "seabird (petrel)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "ocean", "trait": "One of the smallest seabirds, it flutters and 'walks' on the surface to pluck tiny plankton."}, "bird-shearwater": {"name": "Shearwater", "cat": "seabird", "group": "seabird (petrel)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "It shears low over the waves on stiff wings and undertakes vast looping migrations across whole oceans."}, "bird-fulmar": {"name": "Northern fulmar", "cat": "seabird", "group": "seabird (petrel)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "ocean", "trait": "To defend itself it can spit a foul-smelling stomach oil at intruders."}, "bird-pelagic-auklet": {"name": "Auklet", "cat": "seabird", "group": "seabird (auk)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "ocean", "trait": "Small and abundant in northern seas, it gathers plankton in huge flocks and nests in rocky crevices."}, "bird-oystercatcher": {"name": "Oystercatcher", "cat": "seabird", "group": "shorebird (seabird)", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "crabs and shellfish", "art": "ocean", "trait": "Its strong chisel-like bill pries open mussels and oysters along the tideline."}, "cnid-moonjelly": {"name": "Moon jelly", "cat": "cnidarian", "group": "cnidarian (jellyfish)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "jelly", "trait": "Its four horseshoe-shaped gonads show through a clear bell as it drifts, gently pulsing to stay near the surface."}, "cnid-lionsmane": {"name": "Lion's mane jelly", "cat": "cnidarian", "group": "cnidarian (jellyfish)", "hab": "cold polar seas", "habKey": "polar", "diet": "plankton", "art": "jelly", "trait": "The largest known jellyfish, its mass of fine, stinging tentacles can trail many meters behind the bell."}, "cnid-boxjelly": {"name": "Box jellyfish", "cat": "cnidarian", "group": "cnidarian (jellyfish)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "jelly", "trait": "Among the most venomous animals, it has true eyes and swims actively rather than just drifting."}, "cnid-portuguese": {"name": "Portuguese man o' war", "cat": "cnidarian", "group": "cnidarian (siphonophore)", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "jelly", "trait": "Not a single animal but a colony, it sails on a gas-filled float with stinging tentacles hanging below."}, "cnid-seawasp": {"name": "Irukandji jellyfish", "cat": "cnidarian", "group": "cnidarian (jellyfish)", "hab": "warm tropical seas", "habKey": "tropic", "diet": "plankton", "art": "jelly", "trait": "Tiny but extremely venomous, this thumbnail-sized box jelly delivers a sting with severe delayed effects."}, "cnid-cannonball": {"name": "Cannonball jelly", "cat": "cnidarian", "group": "cnidarian (jellyfish)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "jelly", "trait": "A firm, round jelly with a mild sting, it is harvested as food in some regions."}, "cnid-seaanemone": {"name": "Sea anemone", "cat": "cnidarian", "group": "cnidarian (anemone)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "jelly", "trait": "A flower-like predator anchored to rock, it stuns prey with stinging tentacles and can host clownfish."}, "cnid-tubeanemone": {"name": "Tube anemone", "cat": "cnidarian", "group": "cnidarian (anemone)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "plankton", "art": "jelly", "trait": "It builds a soft tube in the seabed and withdraws into it in a flash when disturbed."}, "cnid-staghorn": {"name": "Staghorn coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "A fast-growing, branching reef-builder, it gets much of its food from algae living inside its tissues."}, "cnid-elkhorn": {"name": "Elkhorn coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Its broad antler-like branches once dominated Caribbean reefs but are now threatened."}, "cnid-braincoral": {"name": "Brain coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Its maze-like grooves give it a brain-like look, and it grows slowly into massive, long-lived boulders."}, "cnid-firecoral": {"name": "Fire coral", "cat": "cnidarian", "group": "cnidarian (hydrozoan)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Not a true coral but a relative, it delivers a burning sting to careless swimmers."}, "cnid-softcoral": {"name": "Soft coral", "cat": "cnidarian", "group": "cnidarian (soft coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Lacking a hard skeleton, it sways in the current and is stiffened by tiny embedded mineral spikes."}, "cnid-seafan": {"name": "Sea fan (gorgonian)", "cat": "cnidarian", "group": "cnidarian (soft coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "It grows as a flat, branching fan oriented across the current to catch drifting plankton."}, "cnid-seapen": {"name": "Sea pen", "cat": "cnidarian", "group": "cnidarian (octocoral)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "plankton", "art": "jelly", "trait": "Shaped like an old quill pen, this colony anchors in soft sediment and can glow when disturbed."}, "cnid-blackcoral": {"name": "Black coral", "cat": "cnidarian", "group": "cnidarian (coral)", "hab": "the deep sea", "habKey": "deep", "diet": "plankton", "art": "deepsea", "trait": "Slow-growing in deep water, some colonies are among the oldest animals on Earth, living thousands of years."}, "cnid-hydroid": {"name": "Hydroid", "cat": "cnidarian", "group": "cnidarian (hydrozoan)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "plankton", "art": "jelly", "trait": "Feathery colonies of tiny polyps coat rocks and seaweed, catching plankton with stinging cells."}, "cnid-bluebottle-bythewind": {"name": "By-the-wind sailor", "cat": "cnidarian", "group": "cnidarian (hydrozoan)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "jelly", "trait": "A small floating colony with a stiff sail that catches the wind, often washing ashore in great numbers."}, "cnid-combjelly": {"name": "Comb jelly (ctenophore)", "cat": "cnidarian", "group": "comb jelly", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "jelly", "trait": "It swims with shimmering rows of beating combs and catches prey with sticky cells rather than stings."}, "ceph-giantpacific": {"name": "Giant Pacific octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "crabs and shellfish", "art": "octopus", "trait": "The largest octopus, it is a clever escape artist that can squeeze its boneless body through any gap bigger than its beak."}, "ceph-common": {"name": "Common octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "octopus", "trait": "A problem-solver that opens jars and uses shells as shelter, it can change color and texture in an instant."}, "ceph-bluering": {"name": "Blue-ringed octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "octopus", "trait": "Tiny but deadly, it flashes electric-blue rings as a warning and carries a powerful paralytic toxin."}, "ceph-mimic": {"name": "Mimic octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "octopus", "trait": "It can impersonate other animals, such as a flatfish, lionfish or sea snake, by reshaping its body and posture."}, "ceph-dumbo": {"name": "Dumbo octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "small invertebrates", "art": "deepsea", "trait": "Named for ear-like fins, it is among the deepest-living octopuses, flapping gently above the abyssal floor."}, "ceph-coconut": {"name": "Coconut octopus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "octopus", "trait": "It carries coconut or clam shells to assemble into portable armor, a rare example of tool use in an invertebrate."}, "ceph-giantsquid": {"name": "Giant squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "One of the largest invertebrates, with eyes the size of dinner plates, it was first filmed alive only recently."}, "ceph-colossal": {"name": "Colossal squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "The heaviest invertebrate, it has swiveling hooks on its arms and the largest eyes of any known animal."}, "ceph-humboldt": {"name": "Humboldt squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "fish", "art": "deepsea", "trait": "A large, aggressive hunter that gathers in huge shoals and flashes red and white, earning the nickname 'red devil.'"}, "ceph-vampire": {"name": "Vampire squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "Neither squid nor octopus, this deep-sea relict eats sinking 'marine snow' and can turn itself inside out to hide."}, "ceph-bobtail": {"name": "Bobtail squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "octopus", "trait": "It hides its silhouette using glowing bacteria housed in a special light organ, matching the moonlight above."}, "ceph-reefsquid": {"name": "Caribbean reef squid", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "octopus", "trait": "It communicates with rippling color patterns and can even send different signals from each side of its body."}, "ceph-cuttlefish": {"name": "Cuttlefish", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "octopus", "trait": "A camouflage champion, it controls its skin with split-second precision and floats using a porous internal 'cuttlebone.'"}, "ceph-flamboyant": {"name": "Flamboyant cuttlefish", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "octopus", "trait": "Small and toxic, it pulses with vivid colors and 'walks' along the seabed on arm-like flaps."}, "ceph-nautilus": {"name": "Chambered nautilus", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "A 'living fossil' with a coiled, gas-filled shell, it adjusts its buoyancy by emptying and filling the chambers."}, "ceph-paper-nautilus": {"name": "Argonaut (paper nautilus)", "cat": "mollusc", "group": "mollusc (cephalopod)", "hab": "the open ocean", "habKey": "open", "diet": "jellyfish and soft-bodied animals", "art": "octopus", "trait": "The female secretes a delicate, papery shell that she uses as an egg case and a buoyancy aid."}, "gast-conch": {"name": "Queen conch", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "algae and seaweed", "art": "octopus", "trait": "It grazes algae in seagrass beds and grows a large pink-lipped shell; it moves in odd hops using a claw-like foot."}, "gast-coneshell": {"name": "Cone snail", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "octopus", "trait": "It harpoons prey with a venom-loaded tooth; some species' venom is potent enough to harm humans, but is also studied for medicines."}, "gast-cowrie": {"name": "Cowrie", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "octopus", "trait": "Its glossy shell stays polished because the snail's soft mantle folds up over it; cowries were once used as money."}, "gast-abalone": {"name": "Abalone", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "kelp forests", "habKey": "kelp", "diet": "algae and seaweed", "art": "octopus", "trait": "It clamps to rock with a strong foot and lines its ear-shaped shell with shimmering mother-of-pearl."}, "gast-limpet": {"name": "Limpet", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "octopus", "trait": "It grips rock so tightly that waves cannot dislodge it, and returns to the exact same 'home scar' after grazing."}, "gast-periwinkle": {"name": "Periwinkle", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "octopus", "trait": "A hardy shoreline snail, it seals itself inside its shell to survive being exposed at low tide."}, "gast-whelk": {"name": "Whelk", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "octopus", "trait": "A predatory sea snail, it drills or pries open clams and other shellfish to feed."}, "gast-murex": {"name": "Murex", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "crabs and shellfish", "art": "octopus", "trait": "Spiny and predatory, ancient peoples extracted a precious purple dye from murex snails."}, "gast-tritontrumpet": {"name": "Triton's trumpet", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "coral reefs", "habKey": "reef", "diet": "sea urchins and shellfish", "art": "octopus", "trait": "One of the few predators of the destructive crown-of-thorns starfish, it grows a large trumpet-shaped shell."}, "gast-nudibranch": {"name": "Nudibranch (sea slug)", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "octopus", "trait": "A shell-less, often dazzlingly colorful slug, some steal stinging cells from their prey to reuse in their own defense."}, "gast-spanishdancer": {"name": "Spanish dancer", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "coral reefs", "habKey": "reef", "diet": "sponges", "art": "octopus", "trait": "A large red sea slug that 'dances' by flexing its frilly body to swim through the water."}, "gast-seahare": {"name": "Sea hare", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "algae and seaweed", "art": "octopus", "trait": "When threatened it releases a cloud of purple ink, and it grazes seaweed with ear-like flaps on its head."}, "gast-seabutterfly": {"name": "Sea butterfly (pteropod)", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "octopus", "trait": "A tiny swimming snail that 'flies' through the water on wing-like flaps; its thin shell is vulnerable to ocean acidification."}, "gast-blueglaucus": {"name": "Blue dragon (glaucus)", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "the open ocean", "habKey": "open", "diet": "jellyfish and soft-bodied animals", "art": "octopus", "trait": "It floats upside down at the surface eating venomous siphonophores, then stores their stings for its own defense."}, "gast-seaslug-lettuce": {"name": "Lettuce sea slug", "cat": "mollusc", "group": "mollusc (sea slug)", "hab": "coral reefs", "habKey": "reef", "diet": "sunlight (it makes its own food)", "art": "octopus", "trait": "It keeps working chloroplasts from the algae it eats, letting it make some of its own food from sunlight."}, "biv-giantclam": {"name": "Giant clam", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "coral reefs", "habKey": "reef", "diet": "sunlight (it makes its own food)", "art": "octopus", "trait": "The largest clam, it grows algae in its colorful mantle and gets much of its food from their photosynthesis."}, "biv-scallop": {"name": "Scallop", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "octopus", "trait": "It can swim in bursts by clapping its shells, and rows of tiny blue eyes line the edge of its mantle."}, "biv-oyster": {"name": "Oyster", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "tiny filtered plankton", "art": "octopus", "trait": "It filters and cleans large volumes of water, builds reefs that shelter other life, and can produce pearls."}, "biv-mussel": {"name": "Blue mussel", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "tiny filtered plankton", "art": "octopus", "trait": "It anchors to rock with tough threads it spins, and clusters in dense beds between the tides."}, "biv-cockle": {"name": "Cockle", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "octopus", "trait": "A ribbed, heart-shaped clam, it burrows shallowly and can hop using a strong muscular foot."}, "biv-razor": {"name": "Razor clam", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "octopus", "trait": "Long and narrow, it is a champion burrower, vanishing into wet sand in seconds."}, "biv-shipworm": {"name": "Shipworm", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "detritus and seabed matter", "art": "octopus", "trait": "Not a worm but a clam, it bores into wood and digests it with the help of symbiotic bacteria."}, "biv-pen-shell": {"name": "Pen shell", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "tiny filtered plankton", "art": "octopus", "trait": "A large, fan-shaped clam that stands upright anchored in seagrass beds by fine golden threads."}, "biv-quahog": {"name": "Ocean quahog", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "octopus", "trait": "This slow-growing clam is among the longest-lived animals; one was found to be about five centuries old."}, "biv-angelwing": {"name": "Angel wing clam", "cat": "mollusc", "group": "mollusc (bivalve)", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "tiny filtered plankton", "art": "octopus", "trait": "Its fragile white shell, ribbed like a wing, hides a clam that burrows deep into soft mud."}, "moll-chiton": {"name": "Chiton", "cat": "mollusc", "group": "mollusc (chiton)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "octopus", "trait": "Its shell is made of eight overlapping plates, letting it curl up and grip uneven rock as it grazes algae."}, "crus-hermitcrab": {"name": "Hermit crab", "cat": "crustacean", "group": "crustacean", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "With a soft, vulnerable abdomen, it lives inside an empty snail shell and trades up to bigger shells as it grows."}, "crus-fiddlercrab": {"name": "Fiddler crab", "cat": "crustacean", "group": "crustacean", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "The male waves one greatly enlarged claw to attract mates and warn off rivals on the mudflats."}, "crus-ghostcrab": {"name": "Ghost crab", "cat": "crustacean", "group": "crustacean", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "a wide range of foods", "art": "tidepool", "trait": "Pale and fast, it digs burrows on sandy beaches and is most active at night."}, "crus-bluecrab": {"name": "Blue crab", "cat": "crustacean", "group": "crustacean", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "a wide range of foods", "art": "tidepool", "trait": "A prized seafood species, it swims using paddle-shaped back legs and is a fierce scavenger and predator."}, "crus-dungeness": {"name": "Dungeness crab", "cat": "crustacean", "group": "crustacean", "hab": "the continental shelf", "habKey": "shelf", "diet": "crabs and shellfish", "art": "tidepool", "trait": "A large, sweet-meated crab of the Pacific coast supporting an important fishery."}, "crus-kingcrab": {"name": "King crab", "cat": "crustacean", "group": "crustacean", "hab": "cold polar seas", "habKey": "polar", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "A huge, long-legged crab of cold deep waters, it is among the most valuable seafood catches."}, "crus-snowcrab": {"name": "Snow crab", "cat": "crustacean", "group": "crustacean", "hab": "cold polar seas", "habKey": "polar", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "A cold-water crab with long spindly legs, harvested across the northern seas."}, "crus-spidercrab": {"name": "Japanese spider crab", "cat": "crustacean", "group": "crustacean", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "It has the largest leg span of any arthropod, stretching several meters from claw to claw."}, "crus-coconutcrab": {"name": "Coconut crab", "cat": "crustacean", "group": "crustacean (land)", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "a wide range of foods", "art": "tidepool", "trait": "The largest land arthropod, this giant hermit-crab relative can climb trees and crack open coconuts."}, "crus-porcelaincrab": {"name": "Porcelain crab", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "tidepool", "trait": "It sweeps plankton from the water with feathery mouthparts and sheds a leg easily to escape danger."}, "crus-decoratorcrab": {"name": "Decorator crab", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It camouflages by attaching bits of sponge, algae and anemones to hooks on its shell."}, "crus-spinylobster": {"name": "Spiny lobster", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "Lacking big claws, it relies on spiny armor and migrates in long single-file lines across the seabed."}, "crus-americanlobster": {"name": "American lobster", "cat": "crustacean", "group": "crustacean", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "small invertebrates", "art": "tidepool", "trait": "It wields one heavy crusher claw and one sharp cutter claw, and can live for many decades."}, "crus-slipperlobster": {"name": "Slipper lobster", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "Flat and shovel-nosed, it lacks long antennae and shelters in reef crevices by day."}, "crus-mantisshrimp": {"name": "Mantis shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "tidepool", "trait": "It strikes with club-like limbs so fast they boil the water, and it has some of the most complex eyes known."}, "crus-pistolshrimp": {"name": "Pistol shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "It snaps a specialized claw to create a shockwave loud enough to stun prey."}, "crus-cleanershrimp": {"name": "Cleaner shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "parasites and dead skin", "art": "tidepool", "trait": "It sets up a cleaning station, picking parasites from fish that hold still and even open their mouths for it."}, "crus-krill": {"name": "Antarctic krill", "cat": "crustacean", "group": "crustacean (krill)", "hab": "cold polar seas", "habKey": "polar", "diet": "plankton", "art": "tidepool", "trait": "Tiny but astronomically abundant, swarms of krill feed whales, seals and penguins and form a pillar of the Antarctic food web."}, "crus-copepod": {"name": "Copepod", "cat": "crustacean", "group": "crustacean (plankton)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "tidepool", "trait": "Among the most numerous animals on Earth, these tiny drifters are a key link between phytoplankton and larger animals."}, "crus-amphipod": {"name": "Amphipod", "cat": "crustacean", "group": "crustacean", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "These shrimp-like scavengers swarm whale falls and even thrive in the deepest ocean trenches."}, "crus-isopod-giant": {"name": "Giant isopod", "cat": "crustacean", "group": "crustacean", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "A deep-sea relative of the pillbug, it can grow surprisingly large and survive long stretches between meals."}, "crus-barnacle": {"name": "Barnacle", "cat": "crustacean", "group": "crustacean", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "tiny filtered plankton", "art": "tidepool", "trait": "Cemented head-down to rock, it kicks feathery legs out of its shell to comb plankton from the water."}, "crus-goosebarnacle": {"name": "Goose barnacle", "cat": "crustacean", "group": "crustacean", "hab": "the open ocean", "habKey": "open", "diet": "tiny filtered plankton", "art": "tidepool", "trait": "It attaches by a flexible stalk to floating debris and was once believed to hatch into geese."}, "crus-horseshoecrab": {"name": "Horseshoe crab", "cat": "crustacean", "group": "chelicerate (not a true crab)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "worms and buried invertebrates", "art": "tidepool", "trait": "A 'living fossil' more closely related to spiders than crabs, its blue, copper-based blood is used to test medicines for safety."}, "crus-sandhopper": {"name": "Sand hopper", "cat": "crustacean", "group": "crustacean", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It burrows in damp beach sand by day and emerges at night to feed on washed-up seaweed."}, "echi-seastar": {"name": "Sea star (starfish)", "cat": "echinoderm", "group": "echinoderm", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "crabs and shellfish", "art": "tidepool", "trait": "It can push its stomach out through its mouth to digest prey, and can regrow a lost arm."}, "echi-crownofthorns": {"name": "Crown-of-thorns starfish", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "coral polyps", "art": "tidepool", "trait": "A spiny coral-eater, its population outbreaks can strip large areas of reef."}, "echi-sunflowerstar": {"name": "Sunflower star", "cat": "echinoderm", "group": "echinoderm", "hab": "kelp forests", "habKey": "kelp", "diet": "sea urchins and shellfish", "art": "tidepool", "trait": "One of the largest and fastest sea stars, with up to two dozen arms; its decline has let urchins overgraze kelp."}, "echi-brittlestar": {"name": "Brittle star", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It scuttles surprisingly fast on slender, flexible arms and readily drops an arm to escape predators."}, "echi-basketstar": {"name": "Basket star", "cat": "echinoderm", "group": "echinoderm", "hab": "the deep sea", "habKey": "deep", "diet": "plankton", "art": "deepsea", "trait": "At night it unfurls finely branching arms into a living net to trap drifting plankton."}, "echi-seaurchin": {"name": "Sea urchin", "cat": "echinoderm", "group": "echinoderm", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "tidepool", "trait": "A spiny grazer, it scrapes algae with a five-toothed mouth structure known as 'Aristotle's lantern.'"}, "echi-pencilurchin": {"name": "Slate pencil urchin", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "tidepool", "trait": "Thick, blunt spines like colored pencils protect it and help wedge it into reef crevices."}, "echi-sanddollar": {"name": "Sand dollar", "cat": "echinoderm", "group": "echinoderm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "A flattened urchin relative, it burrows just under the sand and is covered in tiny moving spines in life."}, "echi-seacucumber": {"name": "Sea cucumber", "cat": "echinoderm", "group": "echinoderm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It recycles seafloor sediment as it feeds, and some species eject sticky threads or their own organs to deter predators."}, "echi-featherstar": {"name": "Feather star (crinoid)", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "tidepool", "trait": "An ancient echinoderm, it perches with feathery arms spread to catch plankton and can even swim by waving them."}, "echi-seapig": {"name": "Sea pig", "cat": "echinoderm", "group": "echinoderm", "hab": "the deep sea", "habKey": "deep", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "A plump, pinkish sea cucumber that walks on tube-feet across the abyssal plain, hoovering up nutritious mud."}, "echi-seaapple": {"name": "Sea apple", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "tidepool", "trait": "A colorful sea cucumber that fans out branching tentacles to filter plankton from the current."}, "worm-bristle": {"name": "Bristle worm", "cat": "marine worm", "group": "marine worm (polychaete)", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "Each body segment bears bundles of bristles; some, called fireworms, carry irritating spines for defense."}, "worm-christmastree": {"name": "Christmas tree worm", "cat": "marine worm", "group": "marine worm (polychaete)", "hab": "coral reefs", "habKey": "reef", "diet": "tiny filtered plankton", "art": "deepsea", "trait": "It anchors in coral and fans out two colorful spiral crowns to filter food, snapping them in instantly if disturbed."}, "worm-featherduster": {"name": "Feather duster worm", "cat": "marine worm", "group": "marine worm (polychaete)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "deepsea", "trait": "From a leathery tube it unfurls a feathery crown to strain plankton, withdrawing in a flash when threatened."}, "worm-tubeworm-vent": {"name": "Giant tube worm", "cat": "marine worm", "group": "marine worm (vent)", "hab": "around hydrothermal vents", "habKey": "vent", "diet": "energy from chemicals (via symbiotic bacteria)", "art": "deepsea", "trait": "Living at hydrothermal vents, it has no mouth or gut and is fed entirely by symbiotic bacteria inside its body."}, "worm-osedax": {"name": "Bone-eating worm (Osedax)", "cat": "marine worm", "group": "marine worm", "hab": "the deep sea", "habKey": "deep", "diet": "energy from chemicals (via symbiotic bacteria)", "art": "deepsea", "trait": "These 'zombie worms' bore into the bones of whale falls, mining the fats inside with the help of bacteria."}, "worm-flatworm": {"name": "Marine flatworm", "cat": "marine worm", "group": "marine worm (flatworm)", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "deepsea", "trait": "Paper-thin and often vividly colored, it glides by rippling its edges and some mimic toxic sea slugs."}, "worm-ribbonworm": {"name": "Ribbon worm (nemertean)", "cat": "marine worm", "group": "marine worm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "deepsea", "trait": "It can stretch many times its resting length and shoots out a sticky or venomous proboscis to capture prey."}, "worm-arrowworm": {"name": "Arrow worm", "cat": "marine worm", "group": "marine worm (chaetognath)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "deepsea", "trait": "A transparent planktonic hunter, it seizes tiny prey with grasping spines around its mouth."}, "worm-peanutworm": {"name": "Peanut worm (sipunculan)", "cat": "marine worm", "group": "marine worm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "It can pull its front end inside its body, taking on a peanut-like shape when contracted."}, "worm-innkeeper": {"name": "Innkeeper worm (echiuran)", "cat": "marine worm", "group": "marine worm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "tiny filtered plankton", "art": "deepsea", "trait": "It pumps water through a U-shaped burrow using a mucus net, and other animals lodge in the burrow as 'guests.'"}, "worm-palolo": {"name": "Palolo worm", "cat": "marine worm", "group": "marine worm (polychaete)", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "deepsea", "trait": "On certain moonlit nights its tail segments swarm to the surface in a mass spawning so predictable people harvest them."}, "spng-barrelsponge": {"name": "Giant barrel sponge", "cat": "sponge", "group": "sponge", "hab": "coral reefs", "habKey": "reef", "diet": "tiny filtered plankton", "art": "reef", "trait": "Big enough to sit inside, this slow-growing sponge filters huge volumes of water and can live for centuries."}, "spng-glasssponge": {"name": "Glass sponge", "cat": "sponge", "group": "sponge", "hab": "the deep sea", "habKey": "deep", "diet": "tiny filtered plankton", "art": "deepsea", "trait": "Its skeleton is built of delicate silica glass, and deep-water 'gardens' of them can form on the seafloor."}, "spng-venusflower": {"name": "Venus' flower basket", "cat": "sponge", "group": "sponge", "hab": "the deep sea", "habKey": "deep", "diet": "tiny filtered plankton", "art": "deepsea", "trait": "A lattice of glassy fibers, it often shelters a pair of shrimp that live their whole lives sealed inside."}, "spng-encrusting": {"name": "Encrusting sponge", "cat": "sponge", "group": "sponge", "hab": "coral reefs", "habKey": "reef", "diet": "tiny filtered plankton", "art": "reef", "trait": "It spreads as a colorful crust over rocks and reefs, drawing water in through countless tiny pores."}, "tuni-seasquirt": {"name": "Sea squirt", "cat": "tunicate", "group": "tunicate", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "tiny filtered plankton", "art": "reef", "trait": "A sac-like filter feeder, it squirts water when poked; though it looks like a blob, it is a close relative of vertebrates."}, "tuni-salp": {"name": "Salp", "cat": "tunicate", "group": "tunicate (salp)", "hab": "the open ocean", "habKey": "open", "diet": "tiny filtered plankton", "art": "reef", "trait": "A barrel-shaped drifter that pumps water through its body to feed and can rapidly form long chains."}, "tuni-pyrosome": {"name": "Pyrosome", "cat": "tunicate", "group": "tunicate (colony)", "hab": "the open ocean", "habKey": "open", "diet": "tiny filtered plankton", "art": "reef", "trait": "A tube-shaped colony of thousands of tiny animals, it drifts as one and glows with brilliant bioluminescence."}, "tuni-lightbulb": {"name": "Light bulb tunicate", "cat": "tunicate", "group": "tunicate", "hab": "coral reefs", "habKey": "reef", "diet": "tiny filtered plankton", "art": "reef", "trait": "Named for its glassy, bulb-like bodies, it grows in clusters that filter plankton from the water."}, "plank-diatom": {"name": "Diatom", "cat": "alga or plant", "group": "phytoplankton (diatom)", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "Encased in an ornate, two-part shell of glassy silica, diatoms drift in sunlit water and produce a large share of Earth's oxygen."}, "plank-dinoflagellate": {"name": "Dinoflagellate", "cat": "alga or plant", "group": "phytoplankton (dinoflagellate)", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "These spinning, two-tailed cells include species that cause harmful 'red tides' and others that light the waves with bioluminescence."}, "plank-coccolithophore": {"name": "Coccolithophore", "cat": "alga or plant", "group": "phytoplankton", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "It armors itself in tiny chalk plates, and its blooms can turn whole seas milky and be seen from space."}, "plank-cyanobacteria": {"name": "Prochlorococcus", "cat": "plankton or microbe", "group": "cyanobacteria (microbe)", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "plankton", "trait": "Possibly the most abundant photosynthetic organism on Earth, this microscopic cell helps generate much of the oxygen we breathe."}, "plank-foram": {"name": "Foraminifera", "cat": "plankton or microbe", "group": "plankton (protist)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "plankton", "trait": "It builds a chalky shell, and countless fallen foram shells form thick seafloor ooze that hardens into chalk and limestone."}, "plank-radiolaria": {"name": "Radiolaria", "cat": "plankton or microbe", "group": "plankton (protist)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "plankton", "trait": "These drifters spin intricate, glassy mineral skeletons of astonishing geometric beauty."}, "plank-noctiluca": {"name": "Sea sparkle (Noctiluca)", "cat": "plankton or microbe", "group": "plankton (dinoflagellate)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "plankton", "trait": "When disturbed at night it flashes blue, making breaking waves and boat wakes glow with bioluminescence."}, "plank-trichodesmium": {"name": "Trichodesmium", "cat": "plankton or microbe", "group": "cyanobacteria (microbe)", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "plankton", "trait": "It forms rusty surface slicks sometimes called 'sea sawdust' and pulls nitrogen from the air to fertilize the sea."}, "microbe-virus": {"name": "Marine virus", "cat": "plankton or microbe", "group": "marine microbe (virus)", "hab": "the open ocean", "habKey": "open", "diet": "", "art": "plankton", "trait": "The most numerous biological particles in the sea, marine viruses help recycle nutrients by bursting the microbes they infect."}, "microbe-archaea": {"name": "Marine archaea", "cat": "plankton or microbe", "group": "marine microbe (archaea)", "hab": "around hydrothermal vents", "habKey": "vent", "diet": "energy from chemicals (via symbiotic bacteria)", "art": "deepsea", "trait": "These ancient single-celled microbes thrive in extreme places like hot vents, often living on chemical energy."}, "microbe-bacterioplankton": {"name": "Bacterioplankton", "cat": "plankton or microbe", "group": "marine microbe (bacteria)", "hab": "the open ocean", "habKey": "open", "diet": "detritus and seabed matter", "art": "plankton", "trait": "Invisible but vital, ocean bacteria break down dead matter and recycle nutrients that fuel the entire food web."}, "plank-larva": {"name": "Planktonic larva", "cat": "plankton or microbe", "group": "plankton (animal larva)", "hab": "the open ocean", "habKey": "open", "diet": "plankton", "art": "plankton", "trait": "Many crabs, fish and sea stars begin life as tiny drifting larvae that look nothing like their parents and ride currents to new homes."}, "algae-giantkelp": {"name": "Giant kelp", "cat": "alga or plant", "group": "brown alga (kelp)", "hab": "kelp forests", "habKey": "kelp", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "Among the fastest-growing organisms, it floats on gas-filled bladders to build towering underwater forests."}, "algae-bullkelp": {"name": "Bull kelp", "cat": "alga or plant", "group": "brown alga (kelp)", "hab": "kelp forests", "habKey": "kelp", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "A single round float buoys its long whip-like stalk, and it grows an entire forest in just one season."}, "algae-sargassum": {"name": "Sargassum", "cat": "alga or plant", "group": "brown alga (sargassum)", "hab": "the open ocean", "habKey": "open", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "It floats in vast drifting mats, and the Sargasso Sea it forms shelters baby turtles, crabs and fish far from land."}, "algae-sealettuce": {"name": "Sea lettuce (Ulva)", "cat": "alga or plant", "group": "green alga", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "Thin, translucent green sheets cling to tidal rocks and thrive where nutrients are plentiful."}, "algae-coralline": {"name": "Coralline algae", "cat": "alga or plant", "group": "red alga (calcified)", "hab": "coral reefs", "habKey": "reef", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "It lays down hard limestone, helping cement reefs together and signaling to coral larvae where to settle."}, "algae-nori": {"name": "Nori (Porphyra)", "cat": "alga or plant", "group": "red alga", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "This thin red seaweed is dried into the dark sheets used to wrap sushi."}, "algae-kombu": {"name": "Kombu", "cat": "alga or plant", "group": "brown alga (kelp)", "hab": "shallow coastal waters", "habKey": "coast", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "A thick, edible kelp, it is simmered to make dashi, the savory, umami-rich broth at the heart of Japanese cooking."}, "algae-caulerpa": {"name": "Caulerpa", "cat": "alga or plant", "group": "green alga", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "Remarkably, a sprawling Caulerpa is essentially one giant cell, and some strains have become aggressive invaders."}, "algae-halimeda": {"name": "Halimeda", "cat": "alga or plant", "group": "green alga (calcified)", "hab": "coral reefs", "habKey": "reef", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "Its chalky, segmented joints crumble after death into vast amounts of fine white reef sand."}, "algae-irishmoss": {"name": "Irish moss (Chondrus)", "cat": "alga or plant", "group": "red alga", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "sunlight (it makes its own food)", "art": "kelp", "trait": "A cold-water seaweed, it yields carrageenan, a thickener used in many foods."}, "plant-eelgrass": {"name": "Eelgrass", "cat": "alga or plant", "group": "seagrass (flowering plant)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "A true flowering plant rather than an alga, it forms meadows that nurse young fish and lock away 'blue carbon.'"}, "plant-turtlegrass": {"name": "Turtle grass", "cat": "alga or plant", "group": "seagrass (flowering plant)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "Its broad blades feed sea turtles and manatees and stabilize the seabed across the Caribbean."}, "plant-posidonia": {"name": "Neptune grass (Posidonia)", "cat": "alga or plant", "group": "seagrass (flowering plant)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "Some Mediterranean meadows are single clones thousands of years old, among the oldest living things on Earth."}, "plant-manateegrass": {"name": "Manatee grass", "cat": "alga or plant", "group": "seagrass (flowering plant)", "hab": "seagrass meadows", "habKey": "seagrass", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "Named for its grazers, it has rounded, cylindrical blades unlike most flat-bladed seagrasses."}, "plant-redmangrove": {"name": "Red mangrove", "cat": "alga or plant", "group": "mangrove tree", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "Its arching stilt roots trap sediment, buffer storms and create sheltered nurseries for countless young fish."}, "plant-blackmangrove": {"name": "Black mangrove", "cat": "alga or plant", "group": "mangrove tree", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "sunlight (it makes its own food)", "art": "mangrove", "trait": "It sends up pencil-like roots from the mud to breathe and sheds excess salt through its leaves."}, "plant-cordgrass": {"name": "Saltmarsh cordgrass", "cat": "bony fish", "group": "salt-marsh grass", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "sunlight (it makes its own food)", "art": "reef", "trait": "It engineers entire salt marshes, trapping mud and feeding rich estuarine food webs."}, "fish-hogfish": {"name": "Hogfish", "cat": "bony fish", "group": "wrasse", "hab": "coral reefs", "habKey": "reef", "diet": "crabs and shellfish", "art": "reef", "trait": "It roots in sand with a pig-like snout for shellfish, and every hogfish starts life female before some become male."}, "fish-napoleonwrasse": {"name": "Humphead (Napoleon) wrasse", "cat": "bony fish", "group": "wrasse", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "A giant, long-lived reef fish with a bulbous forehead, it is one of the few predators of the coral-eating crown-of-thorns starfish."}, "fish-dottyback": {"name": "Dottyback", "cat": "bony fish", "group": "dottyback", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "reef", "trait": "Small and pugnacious, some can shift color to blend in with other fish and sneak up on prey."}, "fish-jawfish": {"name": "Jawfish", "cat": "bony fish", "group": "jawfish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "plankton", "art": "reef", "trait": "It digs a pebble-lined burrow and the male broods the eggs in his mouth until they hatch."}, "fish-firefish": {"name": "Firefish (dartfish)", "cat": "bony fish", "group": "dartfish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "It hovers above its burrow snatching plankton and darts back inside at the first sign of danger."}, "fish-tilefish": {"name": "Tilefish", "cat": "bony fish", "group": "tilefish", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "reef", "trait": "It excavates burrows and mounds in the seafloor, creating shelter used by many other animals."}, "fish-wolffish": {"name": "Atlantic wolffish", "cat": "bony fish", "group": "wolffish", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "sea urchins and shellfish", "art": "reef", "trait": "Strong jaws and crushing teeth let it eat urchins and crabs, and it makes a natural antifreeze to survive frigid water."}, "fish-lumpsucker": {"name": "Lumpsucker", "cat": "bony fish", "group": "lumpsucker", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "plankton", "art": "reef", "trait": "A rounded, bumpy fish, it clings to rocks with a suction disc formed from modified fins."}, "fish-sculpin": {"name": "Sculpin", "cat": "bony fish", "group": "sculpin", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "small invertebrates", "art": "reef", "trait": "A big-headed, well-camouflaged bottom fish that ambushes small prey among rocks and tide pools."}, "fish-rockfish": {"name": "Rockfish", "cat": "bony fish", "group": "rockfish", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "fish", "art": "reef", "trait": "Some rockfish live over a century, and many carry venomous spines for defense."}, "fish-greenling": {"name": "Greenling", "cat": "bony fish", "group": "greenling", "hab": "kelp forests", "habKey": "kelp", "diet": "small invertebrates", "art": "reef", "trait": "A patterned fish of kelp and rocky reefs, the male guards the eggs until they hatch."}, "fish-cod": {"name": "Atlantic cod", "cat": "bony fish", "group": "cod", "hab": "the continental shelf", "habKey": "shelf", "diet": "fish", "art": "reef", "trait": "Once supporting some of history's greatest fisheries, it has a chin barbel for sensing food on the bottom."}, "fish-haddock": {"name": "Haddock", "cat": "bony fish", "group": "cod relative", "hab": "the continental shelf", "habKey": "shelf", "diet": "small invertebrates", "art": "reef", "trait": "A bottom-feeding relative of cod, marked by a dark 'thumbprint' spot on each side."}, "fish-pollock": {"name": "Pollock", "cat": "bony fish", "group": "cod relative", "hab": "the continental shelf", "habKey": "shelf", "diet": "fish", "art": "reef", "trait": "A fast-schooling cod relative, it is one of the most heavily fished species in the world."}, "fish-hake": {"name": "Hake", "cat": "bony fish", "group": "cod relative", "hab": "the continental shelf", "habKey": "shelf", "diet": "fish", "art": "reef", "trait": "A slender, deep-water cod relative that rises at night to hunt smaller fish."}, "fish-surfperch": {"name": "Surfperch", "cat": "bony fish", "group": "surfperch", "hab": "shallow coastal waters", "habKey": "coast", "diet": "small invertebrates", "art": "reef", "trait": "Unusual among bony fish, it gives birth to live, fully formed young in the surf zone."}, "fish-blackdrum": {"name": "Black drum", "cat": "bony fish", "group": "drum", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "reef", "trait": "It produces deep drumming sounds with its swim bladder and crushes shellfish with strong throat teeth."}, "fish-croaker": {"name": "Croaker", "cat": "bony fish", "group": "drum", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "reef", "trait": "Named for the croaking noises it makes, it forages over soft bottoms for small invertebrates."}, "fish-reddrum": {"name": "Red drum", "cat": "bony fish", "group": "drum", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "reef", "trait": "A spot near its tail may trick predators into striking the wrong end as it feeds in the shallows."}, "fish-sheepshead": {"name": "Sheepshead", "cat": "bony fish", "group": "porgy relative", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "reef", "trait": "Its broad, human-like teeth crunch through barnacles, crabs and oysters around pilings and rocks."}, "fish-porgy": {"name": "Porgy", "cat": "bony fish", "group": "porgy", "hab": "shallow coastal waters", "habKey": "coast", "diet": "small invertebrates", "art": "reef", "trait": "A deep-bodied coastal fish with strong teeth for crushing small shelled prey."}, "fish-trumpetfish": {"name": "Trumpetfish", "cat": "bony fish", "group": "trumpetfish", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "It hovers head-down among soft corals and even shadows larger fish to sneak up on prey, then sucks it in."}, "fish-cornetfish": {"name": "Cornetfish", "cat": "bony fish", "group": "cornetfish", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "reef", "trait": "Extremely long and thin with a whip-like tail filament, it stalks small fish over reefs and seagrass."}, "fish-pineconefish": {"name": "Pineconefish", "cat": "bony fish", "group": "pineconefish", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "reef", "trait": "Armored in plate-like scales, it carries light organs that glow thanks to symbiotic bacteria."}, "fish-grunion": {"name": "Grunion", "cat": "bony fish", "group": "silverside", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "reef", "trait": "It rides waves onto the beach to spawn in the wet sand on certain moonlit high tides."}, "fish-sandlance": {"name": "Sand lance", "cat": "bony fish", "group": "sand lance", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "plankton", "art": "reef", "trait": "It dives into loose sand to hide and is a crucial forage fish for seabirds, whales and larger fish."}, "fish-icefish": {"name": "Antarctic icefish", "cat": "bony fish", "group": "icefish", "hab": "cold polar seas", "habKey": "polar", "diet": "krill and small crustaceans", "art": "reef", "trait": "It survives sub-zero seas with antifreeze proteins, and remarkably its blood carries no red cells at all."}, "fish-silverside": {"name": "Silverside", "cat": "bony fish", "group": "silverside", "hab": "shallow coastal waters", "habKey": "coast", "diet": "plankton", "art": "reef", "trait": "Small and shiny, it schools near the surface in shallows and is important food for larger predators."}, "shark-bonnethead": {"name": "Bonnethead shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "shark", "trait": "A small, shovel-headed hammerhead, it is the only shark known to deliberately eat and digest seagrass."}, "shark-salmon": {"name": "Salmon shark", "cat": "shark", "group": "shark", "hab": "cold polar seas", "habKey": "polar", "diet": "fish", "art": "shark", "trait": "A warm-bodied, fast Pacific relative of the great white, it thrives in cold northern waters."}, "shark-porbeagle": {"name": "Porbeagle", "cat": "shark", "group": "shark", "hab": "the open ocean", "habKey": "open", "diet": "fish", "art": "shark", "trait": "Stocky and warm-bodied, it is a strong swimmer of cool seas and a close cousin of the mako."}, "shark-sixgill": {"name": "Bluntnose sixgill shark", "cat": "shark", "group": "shark", "hab": "the deep sea", "habKey": "deep", "diet": "fish and squid", "art": "deepsea", "trait": "A large, primitive deep-sea shark with six gill slits instead of the usual five, it rises toward the surface at night."}, "shark-sevengill": {"name": "Broadnose sevengill shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "fish", "art": "shark", "trait": "One of the few sharks with seven gill slits, it hunts cooperatively in kelp beds and bays."}, "shark-swell": {"name": "Swell shark", "cat": "shark", "group": "shark", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "shark", "trait": "When threatened it gulps water to swell up and wedge itself into a crevice so predators cannot remove it."}, "shark-horn": {"name": "Horn shark", "cat": "shark", "group": "shark", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "crabs and shellfish", "art": "shark", "trait": "Small and slow, it crushes hard-shelled prey with flat back teeth and lays spiral-shaped egg cases."}, "shark-bamboo": {"name": "Bamboo shark", "cat": "shark", "group": "carpet shark", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "shark", "trait": "A small, slender bottom shark that can survive low oxygen at low tide and lays tough egg cases."}, "shark-leopard-pacific": {"name": "Leopard shark", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "shark", "trait": "Boldly saddled and spotted, it gathers in large groups over sandy flats and reefs of the Pacific coast."}, "shark-smoothhound": {"name": "Smooth-hound", "cat": "shark", "group": "shark", "hab": "shallow coastal waters", "habKey": "coast", "diet": "crabs and shellfish", "art": "shark", "trait": "A small, harmless coastal shark with flat teeth for grinding up crabs and shellfish."}, "ray-batray": {"name": "Bat ray", "cat": "ray", "group": "ray", "hab": "bays and lagoons", "habKey": "bay", "diet": "crabs and shellfish", "art": "ray", "trait": "It flaps along the bottom of bays and uncovers buried clams by fanning away sand with its wings."}, "ray-pelagic-stingray": {"name": "Pelagic stingray", "cat": "ray", "group": "ray", "hab": "the open ocean", "habKey": "open", "diet": "squid", "art": "ray", "trait": "Unlike most stingrays, it lives out in the open ocean rather than resting on the seabed."}, "crus-stonecrab": {"name": "Stone crab", "cat": "crustacean", "group": "crustacean", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "small invertebrates", "art": "tidepool", "trait": "Fishers harvest just one of its claws and return it alive, since the crab can regrow the missing claw."}, "crus-mudcrab": {"name": "Mangrove mud crab", "cat": "crustacean", "group": "crustacean", "hab": "mangroves and estuaries", "habKey": "mang", "diet": "a wide range of foods", "art": "tidepool", "trait": "A large, powerful crab of mangrove mud, prized as seafood and armed with heavy crushing claws."}, "crus-arrowcrab": {"name": "Arrow crab", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "With a pointed head and impossibly long, spindly legs, it looks like a daddy longlegs of the reef."}, "crus-sallylightfoot": {"name": "Sally Lightfoot crab", "cat": "crustacean", "group": "crustacean", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "a wide range of foods", "art": "tidepool", "trait": "Brightly colored and lightning-fast, it skitters across wave-splashed tropical rocks almost too quick to catch."}, "crus-peacrab": {"name": "Pea crab", "cat": "crustacean", "group": "crustacean", "hab": "shallow coastal waters", "habKey": "coast", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "Tiny and soft, it lives sheltered inside the shells of oysters and mussels, sharing its host's filtered food."}, "crus-boxercrab": {"name": "Boxer (pom-pom) crab", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It carries a small stinging anemone in each claw, waving them like pom-poms to fend off predators."}, "crus-kelpcrab": {"name": "Kelp crab", "cat": "crustacean", "group": "crustacean", "hab": "kelp forests", "habKey": "kelp", "diet": "algae and seaweed", "art": "tidepool", "trait": "It clambers through kelp fronds grazing on algae and can deliver a sharp pinch in defense."}, "crus-boxcrab": {"name": "Box (shame-faced) crab", "cat": "crustacean", "group": "crustacean", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "crabs and shellfish", "art": "tidepool", "trait": "It folds its broad claws over its face like a mask and burrows into sand to hide."}, "crus-harlequinshrimp": {"name": "Harlequin shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "Strikingly patterned, pairs hunt sea stars together, flipping them over to feed slowly on the living animal."}, "crus-bandedcoralshrimp": {"name": "Banded coral shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "parasites and dead skin", "art": "tidepool", "trait": "With long white antennae, it runs a cleaning station, picking parasites from fish that come to be groomed."}, "crus-peppermintshrimp": {"name": "Peppermint shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "small invertebrates", "art": "tidepool", "trait": "Red-striped and helpful in aquariums, it eats nuisance anemones and cleans up scraps."}, "crus-ghostshrimp": {"name": "Ghost shrimp", "cat": "crustacean", "group": "crustacean", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "A pale burrowing shrimp, it digs deep tunnel networks that stir and aerate the seabed."}, "crus-anemoneshrimp": {"name": "Anemone shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "parasites and dead skin", "art": "tidepool", "trait": "Immune to the stings, it lives among anemone tentacles and cleans visiting fish."}, "crus-emperorshrimp": {"name": "Emperor shrimp", "cat": "crustacean", "group": "crustacean", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "It hitches rides on sea cucumbers and sea slugs, gaining transport and a meal of scraps."}, "gast-turbansnail": {"name": "Turban snail", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "octopus", "trait": "It grazes algae on rocky shores and seals its shell with a thick, stony 'cat's eye' trapdoor."}, "gast-topshell": {"name": "Top shell", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "algae and seaweed", "art": "octopus", "trait": "Cone-shaped and pearly within, it scrapes a living from the algae film on tidal rocks."}, "gast-nerite": {"name": "Nerite", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "the intertidal shoreline", "habKey": "shore", "diet": "algae and seaweed", "art": "octopus", "trait": "A small, tough, rounded snail, it endures the pounding intertidal zone while grazing algae from stone."}, "gast-drupe": {"name": "Drupe snail", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "rocky shores and tide pools", "habKey": "rocky", "diet": "small invertebrates", "art": "octopus", "trait": "A predatory rock snail, it drills neat holes through the shells of barnacles and other prey to feed."}, "gast-bubbleshell": {"name": "Bubble shell", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "small invertebrates", "art": "octopus", "trait": "With only a thin, fragile shell, this snail glides over sand engulfing small prey whole."}, "gast-tunshell": {"name": "Tun shell", "cat": "mollusc", "group": "mollusc (gastropod)", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "sea urchins and shellfish", "art": "octopus", "trait": "Carrying a large, thin, lightweight shell, this hunter can secrete acid to subdue urchins and sea cucumbers."}, "cnid-mushroomcoral": {"name": "Mushroom coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Unusually, it lives unattached on the seabed and can slowly move and right itself if flipped over."}, "cnid-bubblecoral": {"name": "Bubble coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "By day it inflates grape-like bubbles, then extends stinging tentacles at night to feed."}, "cnid-suncoral": {"name": "Sun coral", "cat": "cnidarian", "group": "cnidarian (cup coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "Brilliant orange and not reliant on algae, it opens its tentacles mainly at night to capture plankton."}, "cnid-pillarcoral": {"name": "Pillar coral", "cat": "cnidarian", "group": "cnidarian (stony coral)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "It grows in tall finger-like columns and keeps its tentacles out even by day, giving it a furry look."}, "cnid-carpetanemone": {"name": "Carpet anemone", "cat": "cnidarian", "group": "cnidarian (anemone)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "jelly", "trait": "A large, sticky anemone, it hosts clownfish and shrimp while stinging and engulfing prey that lands on it."}, "cnid-magnificentanemone": {"name": "Magnificent anemone", "cat": "cnidarian", "group": "cnidarian (anemone)", "hab": "coral reefs", "habKey": "reef", "diet": "fish", "art": "jelly", "trait": "One of the grandest host anemones, its colorful column shelters clown anemonefish among the tentacles."}, "cnid-zoanthid": {"name": "Zoanthid (button polyps)", "cat": "cnidarian", "group": "cnidarian (zoanthid)", "hab": "coral reefs", "habKey": "reef", "diet": "plankton", "art": "jelly", "trait": "These colonial polyps carpet reef rock in bright mats, and some contain one of the most potent natural toxins known."}, "echi-cushionstar": {"name": "Cushion star", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "Thick and pentagon-shaped, this plump sea star creeps over the reef grazing on films and small organisms."}, "echi-fireurchin": {"name": "Fire urchin", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "tidepool", "trait": "Flamboyantly colored, its venom-tipped spines warn predators away, and tiny animals often shelter among them."}, "echi-flowerurchin": {"name": "Flower urchin", "cat": "echinoderm", "group": "echinoderm", "hab": "coral reefs", "habKey": "reef", "diet": "algae and seaweed", "art": "tidepool", "trait": "Covered in flower-like pincers that inject a painful venom, it is considered one of the most dangerous urchins."}, "echi-hearturchin": {"name": "Heart urchin (sea potato)", "cat": "echinoderm", "group": "echinoderm", "hab": "sandy or muddy seafloor", "habKey": "sand", "diet": "detritus and seabed matter", "art": "tidepool", "trait": "Covered in fine fur-like spines, this heart-shaped urchin lives buried in sand, sifting out tiny food particles."}};
